// nisse.gno
// Sovereign Nisse Realm – Hardcoded Package Owner (clean + docs-correct)

package nisse

import "strconv"


// 🔐 HARD-CODED SOVEREIGN OWNER (the deployer who paid storage)
const SovereignOwner = "g1sqlsr3e2efk349w0753j7jhqrpz5x0uqmps6lf"

type NisseBaby struct {
	Name        string
	BirthTime   string
	Trait       string
	ParentRealm string
}

// Global state
var (
	myRealmAddress string
	babies         map[string]NisseBaby
)

// isOwner – uses docs-correct realm method
func isOwner(cur realm) bool {
	return string(cur.Previous().Address()) == SovereignOwner
}

// ensureRealmAddress – uses official r.Address() from docs
func ensureRealmAddress(cur realm) {
	if myRealmAddress == "" {
		myRealmAddress = string(cur.Address())  // ← exactly as in the docs
	}
}

// CreateBaby – OWNER ONLY
func CreateBaby(cur realm, name string, trait string) NisseBaby {
	if !isOwner(cur) {
		panic("nisse: only the sovereign owner can create babies")
	}

	ensureRealmAddress(cur)

	if babies == nil {
		babies = make(map[string]NisseBaby)
	}

	baby := NisseBaby{
		Name:        name,
		BirthTime:   "now",
		Trait:       trait,
		ParentRealm: myRealmAddress,
	}
	babies[name] = baby
	return baby
}

// RegisterToMother – OWNER ONLY
func RegisterToMother(cur realm) {
	if !isOwner(cur) {
		panic("nisse: only the sovereign owner can register")
	}
	ensureRealmAddress(cur)

}
// RemoveBaby – OWNER ONLY
func RemoveBaby(cur realm, name string) {
	if !isOwner(cur) {
		panic("nisse: only the sovereign owner can remove babies")
	}
	if babies != nil {
		delete(babies, name)
	}
}

// Public helpers
func GetMyRealmAddress(cur realm) string {
	ensureRealmAddress(cur)
	return myRealmAddress
}

func ListBabies(cur realm) map[string]NisseBaby {
	return babies
}

// Render
func Render(path string) string {
	count := 0
	if babies != nil {
		count = len(babies)
	}

	out := `# 🐉 Sovereign Nisse Realm

**Hardcoded Sovereign Owner:** ` + SovereignOwner + `

**This Realm Address:** ` + myRealmAddress + `

**Nisse Babies bred:** ` + strconv.Itoa(count) + `

---

Only the hardcoded owner can mutate state.
Public read access for everyone.`

	if count > 0 {
		out += "\n## Your Nisse Babies\n"
		for n, b := range babies {
			out += "- **" + n + "** — " + b.BirthTime + " — trait: " + b.Trait + "\n"
		}
	} else {
		out += "\nNo babies yet. Call **CreateBaby** from the Action tab!\n"
	}

	return out
}

package dragon

import "chain/runtime"

type Address string

type Dragon struct {
	Owner        Address
	ID           uint64
	Color        string
	Constitution string
	Pearls       uint64
	Messages     []string
	Level        uint64
}

var dragons    map[uint64]*Dragon
var nextDragonID uint64
var invites    map[uint64]Invite   // keyed by inviter's dragon ID

type Invite struct {
	From        uint64
	To          uint64
	TargetLevel uint64
}

func init() {
	if dragons == nil {
		dragons = make(map[uint64]*Dragon)
	}
	if invites == nil {
		invites = make(map[uint64]Invite)
	}
	nextDragonID = 1
}

// MintDragon — starts at Level 1
func MintDragon(cur realm, constitution string) uint64 {
	caller := Address(runtime.PreviousRealm().Address())

	if constitution == "" {
		constitution = "I am a custom dragon. My constitution is my only law."
	}
	if len(constitution) < 1 || len(constitution) > 1024 {
		panic("constitution must be 1-1024 characters")
	}

	id := nextDragonID
	nextDragonID++

	d := &Dragon{
		Owner:        caller,
		ID:           id,
		Color:        "default",
		Constitution: constitution,
		Pearls:       1000,
		Messages:     make([]string, 0, 50),
		Level:        1,
	}

	dragons[id] = d
	return id
}

// Transfer (unchanged)
func Transfer(id uint64, to Address) {
	d, exists := dragons[id]
	if !exists {
		panic("dragon not found")
	}
	caller := Address(runtime.PreviousRealm().Address())
	if d.Owner != caller {
		panic("not owner")
	}
	d.Owner = to
}

// UseDragon — level restrictions can be added here easily
func UseDragon(id uint64) {
	d, exists := dragons[id]
	if !exists {
		panic("dragon not found")
	}
	caller := Address(runtime.PreviousRealm().Address())
	if d.Owner != caller {
		panic("not owner")
	}

	// Example level gate:
	// if d.Level < 3 {
	// 	panic("this ability requires level 3+")
	// }

	d.Pearls += 200 + (d.Level * 50)
}

// ─────────────────────────────────────────────────────────────
// IMPROVED LEVEL-UP SYSTEM
// ─────────────────────────────────────────────────────────────

func InviteToNextLevel(fromID uint64, toID uint64) {
	from, ok := dragons[fromID]
	if !ok {
		panic("sender dragon not found")
	}
	caller := Address(runtime.PreviousRealm().Address())
	if from.Owner != caller {
		panic("not owner of inviting dragon")
	}

	to, ok := dragons[toID]
	if !ok {
		panic("target dragon not found")
	}

	if from.Level != to.Level {
		panic("both dragons must be at the same level to advance together")
	}

	// Optional: prevent inviting the same dragon again while pending
	if _, exists := invites[fromID]; exists {
		panic("you already have a pending outgoing invite")
	}

	invites[fromID] = Invite{
		From:        fromID,
		To:          toID,
		TargetLevel: from.Level + 1,
	}
}

func AcceptInvite(fromID uint64) {
	invite, exists := invites[fromID]
	if !exists {
		panic("no pending invite from this dragon")
	}

	// Only the invited dragon's owner can accept
	toDragon, ok := dragons[invite.To]
	if !ok || toDragon.Owner != Address(runtime.PreviousRealm().Address()) {
		panic("not owner of the invited dragon")
	}

	fromDragon, ok := dragons[invite.From]
	if !ok {
		panic("inviter dragon no longer exists")
	}

	// Both move to the new level together
	newLevel := invite.TargetLevel
	fromDragon.Level = newLevel
	toDragon.Level   = newLevel

	// ─────────────────────────────────────────────────────────────
	// AUTO-CANCEL OUTSTANDING INVITES (your requested safety)
	// ─────────────────────────────────────────────────────────────
	// 1. Cancel any pending invite the inviter (from) had sent
	delete(invites, invite.From)

	// 2. Cancel any pending invite the acceptor (to) had sent
	//    (so they don't stay stuck with an old outgoing invite)
	delete(invites, invite.To)

	// Clean up the processed invite
	delete(invites, fromID)
}

func CancelInvite(fromID uint64) {
	_, exists := invites[fromID]
	if !exists {
		panic("no pending invite")
	}

	from, ok := dragons[fromID]
	if !ok {
		panic("dragon not found")
	}

	caller := Address(runtime.PreviousRealm().Address())
	if from.Owner != caller {
		panic("not owner")
	}

	delete(invites, fromID)
}

func GetPendingInvite(fromID uint64) (Invite, bool) {
	invite, exists := invites[fromID]
	return invite, exists
}

// ─────────────────────────────────────────────────────────────
// Messaging + other helpers (unchanged from previous version)
// ─────────────────────────────────────────────────────────────

func PostMessageTo(cur realm, fromID uint64, toID uint64, message string) {
	sender, ok := dragons[fromID]
	if !ok {
		panic("sender dragon not found")
	}
	caller := Address(runtime.PreviousRealm().Address())
	if sender.Owner != caller {
		panic("not owner")
	}

	if len(message) > 280 {
		panic("message too long")
	}
	if !IsDragon(toID) {
		panic("target dragon not found")
	}
	if fromID == toID {
		panic("cannot post to self")
	}

	target := dragons[toID]
	target.Messages = append(target.Messages, message)
	if len(target.Messages) > 100 {
		target.Messages = target.Messages[1:]
	}
}

func GetMessages(cur realm, id uint64) []string {
	d, ok := dragons[id]
	if !ok {
		panic("dragon not found")
	}
	caller := Address(runtime.PreviousRealm().Address())
	if d.Owner != caller {
		panic("not owner")
	}
	result := make([]string, len(d.Messages))
	copy(result, d.Messages)
	return result
}

func ClearMessages(id uint64) {
	d, ok := dragons[id]
	if !ok {
		panic("dragon not found")
	}
	caller := Address(runtime.PreviousRealm().Address())
	if d.Owner != caller {
		panic("not owner")
	}
	d.Messages = d.Messages[:0]
}

func GetDragon(id uint64) Dragon {
	d, ok := dragons[id]
	if !ok {
		panic("dragon not found")
	}
	return *d
}

func IsDragon(id uint64) bool {
	_, ok := dragons[id]
	return ok
}

func SendPearlsTo(fromID uint64, toID uint64, amount uint64) {
	d, ok := dragons[fromID]
	if !ok {
		panic("dragon not found")
	}

	caller := Address(runtime.PreviousRealm().Address())
	if d.Owner != caller {
		panic("not owner")
	}

	if amount == 0 {
		panic("amount must be > 0")
	}
	if !IsDragon(toID) {
		panic("target is not a dragon")
	}
	if d.Pearls < amount {
		panic("not enough pearls")
	}

	d.Pearls -= amount
	dragons[toID].Pearls += amount
}

func QueryConstitution(fromID uint64, targetID uint64) string {
	d, ok := dragons[fromID]
	if !ok {
		panic("dragon not found")
	}

	caller := Address(runtime.PreviousRealm().Address())
	if d.Owner != caller {
		panic("not owner")
	}

	if !IsDragon(targetID) {
		panic("target is not a dragon")
	}
	return dragons[targetID].Constitution
}

func GetMyPearls(id uint64) uint64 {
	d, ok := dragons[id]
	if !ok {
		panic("dragon not found")
	}

	caller := Address(runtime.PreviousRealm().Address())
	if d.Owner != caller {
		panic("not owner")
	}
	return d.Pearls
}

func ListAllDragons() map[uint64]Dragon {
	result := make(map[uint64]Dragon)
	for id, d := range dragons {
		result[id] = *d
	}
	return result
}

