package fee_split

import (
	"strconv"
	"strings"
)

type Split struct {
	Owner          string
	Recipients     []string
	Shares         []uint64
	Balances       map[string]uint64
	TotalDeposited uint64
	TotalClaimed   uint64
	Frozen         bool
	Archived       bool
}

const (
	MaxRecipients     = 20
	MaxSplitsPerOwner = 10
	MaxSplitsGlobal   = 500
)

var (
	splits      map[string]*Split
	splitIDs    []string
	ownerSplits map[string]int
	nextID      int
)

func init() {
	splits = make(map[string]*Split)
	splitIDs = []string{}
	ownerSplits = make(map[string]int)
	nextID = 1
}

func formatPct(bp uint64) string {
	whole := strconv.FormatUint(bp/100, 10)
	frac := strconv.FormatUint(bp%100, 10)
	if len(frac) == 1 {
		frac = "0" + frac
	}
	return whole + "." + frac + "%"
}

func mustGetSplit(id string) *Split {
	s, ok := splits[id]
	if !ok {
		panic("split not found: " + id)
	}
	return s
}

func mustGetActive(id string) *Split {
	s := mustGetSplit(id)
	if s.Archived {
		panic("split is archived: " + id)
	}
	return s
}

func boolStr(v bool) string {
	if v {
		return "yes"
	}
	return "no"
}

func parseBasisPoints(raw string) []uint64 {
	parts := strings.Split(raw, ",")
	out := make([]uint64, len(parts))
	var total uint64
	for i, s := range parts {
		v, err := strconv.Atoi(strings.TrimSpace(s))
		if err != nil || v <= 0 {
			panic("invalid share value: " + strings.TrimSpace(s))
		}
		out[i] = uint64(v)
		total += uint64(v)
	}
	if total != 10000 {
		panic("shares must sum to 10000 basis points, got " + strconv.FormatUint(total, 10))
	}
	return out
}

func parseAddresses(raw string) []string {
	parts := strings.Split(raw, ",")
	out := make([]string, len(parts))
	for i, r := range parts {
		addr := strings.TrimSpace(r)
		if addr == "" {
			panic("empty recipient address at position " + strconv.Itoa(i))
		}
		out[i] = addr
	}
	return out
}

func CreateSplit(_ realm, owner, recipientList, shareList string) string {
	if len(splits) >= MaxSplitsGlobal {
		panic("global split limit reached")
	}
	if owner == "" {
		panic("owner must not be empty")
	}
	if ownerSplits[owner] >= MaxSplitsPerOwner {
		panic("per-owner split limit reached")
	}

	recipients := parseAddresses(recipientList)
	shares := parseBasisPoints(shareList)

	if len(recipients) != len(shares) {
		panic("recipients and shares must have the same length")
	}
	if len(recipients) == 0 {
		panic("at least one recipient is required")
	}
	if len(recipients) > MaxRecipients {
		panic("too many recipients (max " + strconv.Itoa(MaxRecipients) + ")")
	}

	seen := make(map[string]bool)
	for _, r := range recipients {
		if seen[r] {
			panic("duplicate recipient: " + r)
		}
		seen[r] = true
	}

	id := "split_" + strconv.Itoa(nextID)
	nextID++

	balances := make(map[string]uint64)
	for _, r := range recipients {
		balances[r] = 0
	}

	splits[id] = &Split{
		Owner:      owner,
		Recipients: recipients,
		Shares:     shares,
		Balances:   balances,
	}
	splitIDs = append(splitIDs, id)
	ownerSplits[owner]++
	return id
}

func Deposit(_ realm, splitID string, amount uint64) {
	s := mustGetActive(splitID)
	if s.Frozen {
		panic("split is frozen")
	}
	if amount == 0 {
		panic("amount must be greater than zero")
	}

	s.TotalDeposited += amount

	dustIdx := 0
	for i := 1; i < len(s.Shares); i++ {
		if s.Shares[i] > s.Shares[dustIdx] {
			dustIdx = i
		}
	}

	var distributed uint64
	for i, r := range s.Recipients {
		share := (amount * s.Shares[i]) / 10000
		s.Balances[r] += share
		distributed += share
	}

	dust := amount - distributed
	if dust > 0 {
		s.Balances[s.Recipients[dustIdx]] += dust
	}
}

func Claim(_ realm, splitID, addr string) uint64 {
	s := mustGetActive(splitID)
	bal, exists := s.Balances[addr]
	if !exists {
		panic("not a recipient of this split")
	}
	if bal == 0 {
		panic("nothing to claim")
	}
	s.Balances[addr] = 0
	s.TotalClaimed += bal
	return bal
}

func Freeze(_ realm, splitID, owner string) {
	s := mustGetActive(splitID)
	if owner != s.Owner {
		panic("only the owner can freeze")
	}
	s.Frozen = true
}

func Archive(_ realm, splitID, owner string) {
	s := mustGetActive(splitID)
	if owner != s.Owner {
		panic("only the owner can archive")
	}
	for _, r := range s.Recipients {
		if s.Balances[r] > 0 {
			panic("cannot archive: outstanding balance for " + r)
		}
	}
	s.Archived = true
	ownerSplits[s.Owner]--
	if ownerSplits[s.Owner] <= 0 {
		delete(ownerSplits, s.Owner)
	}
	for i, id := range splitIDs {
		if id == splitID {
			splitIDs = append(splitIDs[:i], splitIDs[i+1:]...)
			break
		}
	}
}

func GetSplitInfo(splitID string) string {
	s := mustGetSplit(splitID)
	var b strings.Builder
	b.WriteString("Split: " + splitID + "\n")
	b.WriteString("Owner: " + s.Owner + "\n")
	b.WriteString("Frozen: " + boolStr(s.Frozen) + "\n")
	b.WriteString("Deposited: " + strconv.FormatUint(s.TotalDeposited, 10) + "\n")
	b.WriteString("Claimed: " + strconv.FormatUint(s.TotalClaimed, 10) + "\n")
	for i, r := range s.Recipients {
		b.WriteString("  " + r + "  " + formatPct(s.Shares[i]) + "  claimable: " + strconv.FormatUint(s.Balances[r], 10) + "\n")
	}
	return b.String()
}

func GetClaimable(splitID, addr string) uint64 {
	s := mustGetSplit(splitID)
	return s.Balances[addr]
}

func Render(path string) string {
	if splits == nil || len(splits) == 0 {
		return "# Fee Split\n\nNo active splits.\n"
	}

	var b strings.Builder
	b.WriteString("# Fee Split\n\n")

	for _, id := range splitIDs {
		s := splits[id]
		if s == nil {
			continue
		}
		b.WriteString("## " + id + "\n\n")
		b.WriteString("Owner: " + s.Owner + "\n")
		b.WriteString("Frozen: " + boolStr(s.Frozen) + "\n")
		b.WriteString("Deposited: " + strconv.FormatUint(s.TotalDeposited, 10) + "\n")
		b.WriteString("Claimed: " + strconv.FormatUint(s.TotalClaimed, 10) + "\n")
		if len(s.Recipients) > 0 {
			for i, r := range s.Recipients {
				b.WriteString("  " + r + "  " + formatPct(s.Shares[i]) + "  claimable: " + strconv.FormatUint(s.Balances[r], 10) + "\n")
			}
		}
		b.WriteString("\n")
	}
	return b.String()
}

package permission_registry

import (
	"sort"
	"strings"
)

var (
	resources     map[string]string
	resourceNames []string
	permissions   map[string]map[string]map[string]bool
	permList      map[string][]string
)

func init() {
	resources = make(map[string]string)
	resourceNames = []string{}
	permissions = make(map[string]map[string]map[string]bool)
	permList = make(map[string][]string)
}

func mustBeAdmin(resource, admin string) {
	stored, exists := resources[resource]
	if !exists {
		panic("resource not found: " + resource)
	}
	if admin != stored {
		panic("permission denied: not admin of " + resource)
	}
}

func CreateResource(_ realm, admin, resourceName string) {
	if resourceName == "" {
		panic("resource name must not be empty")
	}
	if admin == "" {
		panic("admin must not be empty")
	}
	if _, exists := resources[resourceName]; exists {
		panic("resource already exists: " + resourceName)
	}
	resources[resourceName] = admin
	resourceNames = append(resourceNames, resourceName)
	permissions[resourceName] = make(map[string]map[string]bool)
	permList[resourceName] = []string{}
}

func Grant(_ realm, admin, resourceName, permission, addr string) {
	mustBeAdmin(resourceName, admin)
	if permission == "" {
		panic("permission name must not be empty")
	}
	if addr == "" {
		panic("address must not be empty")
	}
	perms := permissions[resourceName]
	if perms[permission] == nil {
		perms[permission] = make(map[string]bool)
		permList[resourceName] = append(permList[resourceName], permission)
	}
	if perms[permission][addr] {
		panic("permission already granted")
	}
	perms[permission][addr] = true
}

func Revoke(_ realm, admin, resourceName, permission, addr string) {
	mustBeAdmin(resourceName, admin)
	perms := permissions[resourceName]
	if perms[permission] == nil || !perms[permission][addr] {
		panic("permission not granted")
	}
	delete(perms[permission], addr)
}

func Has(resourceName, permission, addr string) bool {
	perms, exists := permissions[resourceName]
	if !exists {
		return false
	}
	holders := perms[permission]
	if holders == nil {
		return false
	}
	return holders[addr]
}

func GetAdmin(resourceName string) string {
	admin, exists := resources[resourceName]
	if !exists {
		return "not found"
	}
	return admin
}

func ListResources() string {
	if len(resourceNames) == 0 {
		return "none"
	}
	return strings.Join(resourceNames, ", ")
}

func Render(path string) string {
	if len(resources) == 0 {
		return "# Permission Registry\n\nNo resources registered.\n"
	}
	var b strings.Builder
	b.WriteString("# Permission Registry\n\n")
	for _, name := range resourceNames {
		admin := resources[name]
		b.WriteString("## " + name + "\n\n")
		b.WriteString("**Admin:** `" + admin + "`\n\n")
		perms, exists := permissions[name]
		if !exists || len(perms) == 0 {
			b.WriteString("_No permissions defined._\n\n")
			continue
		}
		b.WriteString("| Permission | Addresses |\n")
		b.WriteString("|------------|-----------|\n")
		for _, perm := range permList[name] {
			holders := perms[perm]
			if holders == nil || len(holders) == 0 {
				continue
			}
			var addrs []string
			for addr := range holders {
				if holders[addr] {
					addrs = append(addrs, addr)
				}
			}
			sort.Strings(addrs)
			for i, a := range addrs {
				addrs[i] = "`" + a + "`"
			}
			b.WriteString("| " + perm + " | " + strings.Join(addrs, ", ") + " |\n")
		}
		b.WriteString("\n")
	}
	return b.String()
}

package service_registry

import (
	"strconv"
	"strings"
)

type Service struct {
	Name        string
	Owner       string
	Description string
	ServiceType string
}

var (
	services map[string]*Service
	names    []string
)

func init() {
	services = make(map[string]*Service)
	names = []string{}
}

func mustGet(name string) *Service {
	svc, ok := services[name]
	if !ok {
		panic("service not found: " + name)
	}
	return svc
}

func RegisterService(_ realm, owner, name, description, serviceType string) {
	if name == "" {
		panic("name must not be empty")
	}
	if owner == "" {
		panic("owner must not be empty")
	}
	if _, exists := services[name]; exists {
		panic("service already registered: " + name)
	}
	services[name] = &Service{
		Name:        name,
		Owner:       owner,
		Description: description,
		ServiceType: serviceType,
	}
	names = append(names, name)
}

func UpdateService(_ realm, owner, name, description, serviceType string) {
	svc := mustGet(name)
	if owner != svc.Owner {
		panic("only the owner can update")
	}
	if description != "" {
		svc.Description = description
	}
	if serviceType != "" {
		svc.ServiceType = serviceType
	}
}

func Deregister(_ realm, owner, name string) {
	svc := mustGet(name)
	if owner != svc.Owner {
		panic("only the owner can deregister")
	}
	delete(services, name)
	for i, n := range names {
		if n == name {
			names = append(names[:i], names[i+1:]...)
			break
		}
	}
}

func GetService(name string) string {
	svc := mustGet(name)
	return "Name: " + svc.Name + " | Owner: " + svc.Owner + " | Type: " + svc.ServiceType + " | " + svc.Description
}

func ListServices() string {
	if len(names) == 0 {
		return "none"
	}
	return strings.Join(names, ", ")
}

func Render(path string) string {
	if len(services) == 0 {
		return "# Service Registry\n\nNo services registered.\n"
	}
	var b strings.Builder
	b.WriteString("# Service Registry\n\n")
	b.WriteString("**Total:** " + strconv.Itoa(len(services)) + "\n\n")
	b.WriteString("| Name | Type | Owner |\n")
	b.WriteString("|------|------|-------|\n")
	for _, name := range names {
		svc := services[name]
		if svc == nil {
			continue
		}
		b.WriteString("| " + svc.Name + " | " + svc.ServiceType + " | `" + svc.Owner + "` |\n")
	}
	return b.String()
}

package timelock_guardian

import (
	"strconv"
	"strings"
)

type Action struct {
	ID          string
	Creator     string
	Target      string
	Data        string
	CreatedAt   int64
	ExecuteAt   int64
	Executed    bool
	Cancelled   bool
}

var (
	actions   map[string]*Action
	actionIDs []string
	nextID    int
	curBlock  int64
)

func init() {
	actions = make(map[string]*Action)
	actionIDs = []string{}
	nextID = 1
	curBlock = 0
}

func mustGet(id string) *Action {
	a, ok := actions[id]
	if !ok {
		panic("action not found: " + id)
	}
	return a
}

func SetBlock(_ realm, height int64) {
	if height < 0 {
		panic("block height must be non-negative")
	}
	curBlock = height
}

func Schedule(_ realm, creator, target, data string, delay int64) string {
	if target == "" {
		panic("target must not be empty")
	}
	if delay <= 0 {
		panic("delay must be positive")
	}

	id := "action_" + strconv.Itoa(nextID)
	nextID++

	actions[id] = &Action{
		ID:        id,
		Creator:   creator,
		Target:    target,
		Data:      data,
		CreatedAt: curBlock,
		ExecuteAt: curBlock + delay,
	}
	actionIDs = append(actionIDs, id)
	return id
}

func Execute(_ realm, actionID string) string {
	a := mustGet(actionID)
	if a.Cancelled {
		panic("action is cancelled")
	}
	if a.Executed {
		panic("action already executed")
	}
	if curBlock < a.ExecuteAt {
		remaining := a.ExecuteAt - curBlock
		panic("too early: " + strconv.FormatInt(remaining, 10) + " blocks remaining")
	}
	a.Executed = true
	return "executed: " + actionID
}

func Cancel(_ realm, creator, actionID string) {
	a := mustGet(actionID)
	if a.Creator != creator {
		panic("only the creator can cancel")
	}
	if a.Executed {
		panic("cannot cancel executed action")
	}
	if a.Cancelled {
		panic("already cancelled")
	}
	a.Cancelled = true
}

func GetAction(actionID string) string {
	a := mustGet(actionID)
	status := "pending"
	if a.Cancelled {
		status = "cancelled"
	} else if a.Executed {
		status = "executed"
	} else if curBlock >= a.ExecuteAt {
		status = "ready"
	}
	return "ID: " + a.ID + " | Creator: " + a.Creator + " | Target: " + a.Target + " | Status: " + status
}

func IsReady(actionID string) bool {
	a, ok := actions[actionID]
	if !ok || a.Executed || a.Cancelled {
		return false
	}
	return curBlock >= a.ExecuteAt
}

func Render(path string) string {
	if len(actions) == 0 {
		return "# Timelock Guardian\n\nNo actions scheduled.\n"
	}
	var b strings.Builder
	b.WriteString("# Timelock Guardian\n\n")
	b.WriteString("**Block:** " + strconv.FormatInt(curBlock, 10) + "\n\n")

	for _, id := range actionIDs {
		a := actions[id]
		if a == nil {
			continue
		}
		status := "pending"
		if a.Cancelled {
			status = "cancelled"
		} else if a.Executed {
			status = "executed"
		} else if curBlock >= a.ExecuteAt {
			status = "**ready**"
		}
		b.WriteString("- **" + a.ID + "** | " + a.Target + " | " + status + "\n")
	}
	return b.String()
}

package upgrade_registry

import (
	"strconv"
	"strings"
)

type ContractEntry struct {
	Address    string
	Owner      string
	Name       string
	Deprecated bool
	Successor  string
}

var (
	entries    map[string]*ContractEntry
	entryAddrs []string
)

func init() {
	entries = make(map[string]*ContractEntry)
	entryAddrs = []string{}
}

func Register(_ realm, owner, contractAddr, name string) string {
	if contractAddr == "" || name == "" || owner == "" {
		panic("owner, contractAddr, and name must not be empty")
	}
	if _, exists := entries[contractAddr]; exists {
		panic("contract already registered: " + contractAddr)
	}
	entries[contractAddr] = &ContractEntry{
		Address: contractAddr,
		Owner:   owner,
		Name:    name,
	}
	entryAddrs = append(entryAddrs, contractAddr)
	return "registered " + name
}

func Deprecate(_ realm, owner, contractAddr, successorAddr string) string {
	entry, exists := entries[contractAddr]
	if !exists {
		panic("contract not found")
	}
	if entry.Owner != owner {
		panic("only the owner can deprecate")
	}
	if entry.Deprecated {
		panic("already deprecated")
	}
	if successorAddr == contractAddr {
		panic("successor cannot be self")
	}
	entry.Deprecated = true
	entry.Successor = successorAddr
	return "deprecated " + entry.Name
}

func GetLatest(contractAddr string) string {
	visited := make(map[string]bool)
	current := contractAddr
	for {
		entry, exists := entries[current]
		if !exists {
			return current
		}
		if !entry.Deprecated || entry.Successor == "" {
			return current
		}
		if visited[current] {
			return current
		}
		visited[current] = true
		current = entry.Successor
	}
}

func GetInfo(contractAddr string) string {
	entry, exists := entries[contractAddr]
	if !exists {
		panic("contract not found")
	}
	status := "active"
	if entry.Deprecated {
		status = "deprecated -> " + entry.Successor
	}
	return entry.Name + " | owner: " + entry.Owner + " | " + status
}

func Render(path string) string {
	if len(entries) == 0 {
		return "# Upgrade Registry\n\nNo contracts registered.\n"
	}
	var b strings.Builder
	b.WriteString("# Upgrade Registry\n\n")
	b.WriteString("**Total:** " + strconv.Itoa(len(entries)) + "\n\n")
	for _, addr := range entryAddrs {
		entry := entries[addr]
		if entry == nil {
			continue
		}
		line := "- **" + entry.Name + "** (`" + addr + "`) — owner: `" + entry.Owner + "`"
		if entry.Deprecated {
			line += " — DEPRECATED -> `" + entry.Successor + "`"
		}
		b.WriteString(line + "\n")
	}
	return b.String()
}

package poker

// Deck manages a 52-card deck with deterministic shuffling
type Deck struct {
	Cards []Card
	Index int // Current deal position
}

// NewDeck creates a standard 52-card deck
func NewDeck() *Deck {
	cards := make([]Card, 52)
	idx := 0
	for suit := 0; suit < 4; suit++ {
		for value := 2; value <= 14; value++ {
			cards[idx] = Card{Suit: suit, Value: value}
			idx++
		}
	}
	return &Deck{Cards: cards, Index: 0}
}

// Shuffle shuffles the deck using a seed-based Fisher-Yates algorithm
// This is deterministic given the same seed, which is important for
// blockchain reproducibility. In production, the seed should come from
// a commit-reveal scheme where all players contribute randomness.
func (d *Deck) Shuffle(seed int64) {
	n := len(d.Cards)
	// Simple LCG (Linear Congruential Generator) for deterministic randomness
	state := seed
	for i := n - 1; i > 0; i-- {
		// LCG: state = (a * state + c) mod m
		state = (state*6364136223846793005 + 1442695040888963407) % (1 << 62)
		j := int(abs64(state) % int64(i+1))
		d.Cards[i], d.Cards[j] = d.Cards[j], d.Cards[i]
	}
	d.Index = 0
}

// Deal deals n cards from the deck
func (d *Deck) Deal(n int) []Card {
	if d.Index+n > len(d.Cards) {
		panic("not enough cards in deck")
	}
	cards := make([]Card, n)
	for i := 0; i < n; i++ {
		cards[i] = d.Cards[d.Index]
		d.Index++
	}
	return cards
}

// DealOne deals a single card from the deck
func (d *Deck) DealOne() Card {
	cards := d.Deal(1)
	return cards[0]
}

// Remaining returns the number of cards remaining in the deck
func (d *Deck) Remaining() int {
	return len(d.Cards) - d.Index
}

// Reset resets the deck to the beginning
func (d *Deck) Reset() {
	d.Index = 0
}

func abs64(x int64) int64 {
	if x < 0 {
		return -x
	}
	return x
}

package poker

// EvaluateHand evaluates the best 5-card poker hand from 7 cards
// (2 hole cards + 5 community cards)
func EvaluateHand(holeCards [2]Card, community []Card) HandResult {
	// Combine all available cards
	allCards := make([]Card, 0, 7)
	allCards = append(allCards, holeCards[0], holeCards[1])
	allCards = append(allCards, community...)

	if len(allCards) < 5 {
		return HandResult{Rank: HighCard}
	}

	// Generate all C(n, 5) combinations and find the best hand
	best := HandResult{Rank: HighCard}
	n := len(allCards)

	for i := 0; i < n-4; i++ {
		for j := i + 1; j < n-3; j++ {
			for k := j + 1; k < n-2; k++ {
				for l := k + 1; l < n-1; l++ {
					for m := l + 1; m < n; m++ {
						hand := [5]Card{allCards[i], allCards[j], allCards[k], allCards[l], allCards[m]}
						result := evaluate5(hand)
						if compareHands(result, best) > 0 {
							best = result
						}
					}
				}
			}
		}
	}

	return best
}

// evaluate5 evaluates exactly 5 cards
func evaluate5(cards [5]Card) HandResult {
	// Sort cards by value descending
	sorted := sortCards(cards)

	isFlush := checkFlush(sorted)
	isStraight, highCard := checkStraight(sorted)

	// Count value occurrences
	counts := make(map[int]int)
	for _, c := range sorted {
		counts[c.Value]++
	}

	// Classify hand
	if isFlush && isStraight {
		if highCard == 14 {
			return HandResult{Rank: RoyalFlush, TieBreak: [5]int{14, 0, 0, 0, 0}, BestCards: sorted}
		}
		return HandResult{Rank: StraightFlush, TieBreak: [5]int{highCard, 0, 0, 0, 0}, BestCards: sorted}
	}

	// Four of a kind
	if hasNOfAKind(counts, 4) {
		quad := getValuesWithCount(counts, 4)
		kicker := getValuesWithCount(counts, 1)
		return HandResult{
			Rank:      FourOfAKind,
			TieBreak:  [5]int{quad[0], kicker[0], 0, 0, 0},
			BestCards: sorted,
		}
	}

	// Full house
	if hasNOfAKind(counts, 3) && hasNOfAKind(counts, 2) {
		trips := getValuesWithCount(counts, 3)
		pair := getValuesWithCount(counts, 2)
		return HandResult{
			Rank:      FullHouse,
			TieBreak:  [5]int{trips[0], pair[0], 0, 0, 0},
			BestCards: sorted,
		}
	}

	if isFlush {
		return HandResult{
			Rank:      Flush,
			TieBreak:  [5]int{sorted[0].Value, sorted[1].Value, sorted[2].Value, sorted[3].Value, sorted[4].Value},
			BestCards: sorted,
		}
	}

	if isStraight {
		return HandResult{
			Rank:      Straight,
			TieBreak:  [5]int{highCard, 0, 0, 0, 0},
			BestCards: sorted,
		}
	}

	// Three of a kind
	if hasNOfAKind(counts, 3) {
		trips := getValuesWithCount(counts, 3)
		kickers := getValuesWithCount(counts, 1)
		sortDescending(kickers)
		tb := [5]int{trips[0], 0, 0, 0, 0}
		for i, v := range kickers {
			if i+1 < 5 {
				tb[i+1] = v
			}
		}
		return HandResult{Rank: ThreeOfAKind, TieBreak: tb, BestCards: sorted}
	}

	// Two pair
	pairs := getValuesWithCount(counts, 2)
	if len(pairs) == 2 {
		sortDescending(pairs)
		kickers := getValuesWithCount(counts, 1)
		return HandResult{
			Rank:      TwoPair,
			TieBreak:  [5]int{pairs[0], pairs[1], kickers[0], 0, 0},
			BestCards: sorted,
		}
	}

	// One pair
	if len(pairs) == 1 {
		kickers := getValuesWithCount(counts, 1)
		sortDescending(kickers)
		tb := [5]int{pairs[0], 0, 0, 0, 0}
		for i, v := range kickers {
			if i+1 < 5 {
				tb[i+1] = v
			}
		}
		return HandResult{Rank: OnePair, TieBreak: tb, BestCards: sorted}
	}

	// High card
	return HandResult{
		Rank:      HighCard,
		TieBreak:  [5]int{sorted[0].Value, sorted[1].Value, sorted[2].Value, sorted[3].Value, sorted[4].Value},
		BestCards: sorted,
	}
}

// compareHands compares two hand results: returns >0 if a is better, <0 if b is better, 0 if equal
func compareHands(a, b HandResult) int {
	if a.Rank != b.Rank {
		return int(a.Rank) - int(b.Rank)
	}
	for i := 0; i < 5; i++ {
		if a.TieBreak[i] != b.TieBreak[i] {
			return a.TieBreak[i] - b.TieBreak[i]
		}
	}
	return 0
}

// CompareHandResults is exported for use in the realm
func CompareHandResults(a, b HandResult) int {
	return compareHands(a, b)
}

// Helper functions

func sortCards(cards [5]Card) [5]Card {
	sorted := cards
	for i := 0; i < 4; i++ {
		for j := i + 1; j < 5; j++ {
			if sorted[j].Value > sorted[i].Value {
				sorted[i], sorted[j] = sorted[j], sorted[i]
			}
		}
	}
	return sorted
}

func checkFlush(cards [5]Card) bool {
	suit := cards[0].Suit
	for i := 1; i < 5; i++ {
		if cards[i].Suit != suit {
			return false
		}
	}
	return true
}

func checkStraight(cards [5]Card) (bool, int) {
	// Normal straight check (cards are sorted descending)
	isSeq := true
	for i := 0; i < 4; i++ {
		if cards[i].Value-cards[i+1].Value != 1 {
			isSeq = false
			break
		}
	}
	if isSeq {
		return true, cards[0].Value
	}

	// Check for A-2-3-4-5 (wheel)
	if cards[0].Value == 14 && cards[1].Value == 5 && cards[2].Value == 4 && cards[3].Value == 3 && cards[4].Value == 2 {
		return true, 5 // 5-high straight
	}

	return false, 0
}

func hasNOfAKind(counts map[int]int, n int) bool {
	for _, c := range counts {
		if c == n {
			return true
		}
	}
	return false
}

func getValuesWithCount(counts map[int]int, n int) []int {
	result := []int{}
	for v, c := range counts {
		if c == n {
			result = append(result, v)
		}
	}
	sortDescending(result)
	return result
}

func sortDescending(arr []int) {
	for i := 0; i < len(arr)-1; i++ {
		for j := i + 1; j < len(arr); j++ {
			if arr[j] > arr[i] {
				arr[i], arr[j] = arr[j], arr[i]
			}
		}
	}
}

package poker

// Address is a string alias for wallet addresses
type Address = string

// Card represents a playing card
type Card struct {
	Suit  int // 0=Spades, 1=Hearts, 2=Diamonds, 3=Clubs
	Value int // 2-14 (14=Ace)
}

// Player represents a player at the table
type Player struct {
	Address    Address
	Hand       [2]Card
	Chips      int64
	CurrentBet int64
	HasFolded  bool
	IsAllIn    bool
	IsActive   bool
	SeatIndex  int
}

// GameState represents the current phase of a hand
type GameState int

const (
	StateWaiting  GameState = 0 // Waiting for players
	StatePreFlop  GameState = 1 // Hole cards dealt, pre-flop betting
	StateFlop     GameState = 2 // Flop dealt (3 community cards)
	StateTurn     GameState = 3 // Turn dealt (4th community card)
	StateRiver    GameState = 4 // River dealt (5th community card)
	StateShowdown GameState = 5 // All betting complete, determine winner
)

func (gs GameState) String() string {
	switch gs {
	case StateWaiting:
		return "Waiting"
	case StatePreFlop:
		return "Pre-Flop"
	case StateFlop:
		return "Flop"
	case StateTurn:
		return "Turn"
	case StateRiver:
		return "River"
	case StateShowdown:
		return "Showdown"
	default:
		return "Unknown"
	}
}

// Table represents a poker table
type Table struct {
	ID            string
	Name          string
	Creator       Address
	Players       []*Player
	MaxPlayers    int   // 4 or 6
	SmallBlind    int64 // in ugnot (e.g., 2500000 = 2.5 GNOT)
	BigBlind      int64 // in ugnot (e.g., 5000000 = 5 GNOT)
	MinBet        int64 // minimum raise amount
	MaxBet        int64 // maximum single bet
	MinBuyIn      int64 // minimum chips to join
	MaxBuyIn      int64 // maximum chips to join
	Pot           int64
	Community     []Card
	State         GameState
	DealerIdx     int    // Dealer button position
	CurrentTurn   int    // Index of player whose turn it is
	DeckSeed      int64  // Seed for deck shuffle
	HandCount     int    // Number of hands played
	RakeCollected int64  // Total rake collected at this table
}

// HandRank represents the rank of a poker hand
type HandRank int

const (
	HighCard      HandRank = 0
	OnePair       HandRank = 1
	TwoPair       HandRank = 2
	ThreeOfAKind  HandRank = 3
	Straight      HandRank = 4
	Flush         HandRank = 5
	FullHouse     HandRank = 6
	FourOfAKind   HandRank = 7
	StraightFlush HandRank = 8
	RoyalFlush    HandRank = 9
)

func (hr HandRank) String() string {
	switch hr {
	case HighCard:
		return "High Card"
	case OnePair:
		return "One Pair"
	case TwoPair:
		return "Two Pair"
	case ThreeOfAKind:
		return "Three of a Kind"
	case Straight:
		return "Straight"
	case Flush:
		return "Flush"
	case FullHouse:
		return "Full House"
	case FourOfAKind:
		return "Four of a Kind"
	case StraightFlush:
		return "Straight Flush"
	case RoyalFlush:
		return "Royal Flush"
	default:
		return "Unknown"
	}
}

// HandResult stores the evaluated hand result for comparison
type HandResult struct {
	Rank      HandRank
	TieBreak  [5]int // Values for breaking ties, highest first
	BestCards [5]Card
}

// SuitName returns the name of a suit
func SuitName(suit int) string {
	switch suit {
	case 0:
		return "♠"
	case 1:
		return "♥"
	case 2:
		return "♦"
	case 3:
		return "♣"
	default:
		return "?"
	}
}

// ValueName returns the display name of a card value
func ValueName(value int) string {
	switch value {
	case 11:
		return "J"
	case 12:
		return "Q"
	case 13:
		return "K"
	case 14:
		return "A"
	default:
		if value >= 2 && value <= 10 {
			return IntToStr(value)
		}
		return "?"
	}
}

// CardString returns a human-readable string for a card
func CardString(c Card) string {
	return ValueName(c.Value) + SuitName(c.Suit)
}

// IntToStr converts an integer to a string
func IntToStr(n int) string {
	if n == 0 {
		return "0"
	}
	s := ""
	neg := false
	if n < 0 {
		neg = true
		n = -n
	}
	for n > 0 {
		digit := n % 10
		s = string(rune('0'+digit)) + s
		n /= 10
	}
	if neg {
		s = "-" + s
	}
	return s
}

package poker

import (
	"chain"
	"chain/banker"
	"chain/runtime"
	"strings"

	"gno.land/p/demo/poker"
)

// ----- State -----
var (
	tables      map[string]*poker.Table
	tableList   []string
	admin       address
	rakePercent int64
	rakePool    int64
	tableCount  int
	deposits    map[string]int64 // address -> deposited ugnot
)

func init() {
	tables = make(map[string]*poker.Table)
	deposits = make(map[string]int64)
	admin = runtime.PreviousRealm().Address()
	rakePercent = 300 // 3% default
}

// RealmAddr returns the realm's address for MsgSend deposits
func RealmAddr() string {
	return runtime.CurrentRealm().Address().String()
}

// Deposit is called after MsgSend to register the deposit
// The caller first sends GNOT via MsgSend to RealmAddr(),
// then calls Deposit() to register it
func Deposit(cur realm) int64 {
	caller := runtime.PreviousRealm().Address()
	b := banker.NewBanker(banker.BankerTypeReadonly)
	pkgaddr := runtime.CurrentRealm().Address()
	realmCoins := b.GetCoins(pkgaddr)
	var realmBalance int64
	for _, c := range realmCoins {
		if c.Denom == "ugnot" {
			realmBalance = c.Amount
			break
		}
	}
	// Track total deposited by this caller
	deposits[caller.String()] = realmBalance
	return realmBalance
}

// GetDeposit returns how much a player has deposited
func GetDeposit(addr string) int64 {
	return deposits[addr]
}



// ----- Lobby Functions -----

func CreateTable(cur realm, name string, smallBlind int64, bigBlind int64, minBet int64, maxBet int64, maxPlayers int, minBuyIn int64) string {
	caller := runtime.PreviousRealm().Address()

	if maxPlayers != 4 && maxPlayers != 6 {
		panic("maxPlayers must be 4 or 6")
	}
	if smallBlind <= 0 || bigBlind <= 0 || smallBlind > bigBlind {
		panic("invalid blind structure")
	}
	if minBet <= 0 || maxBet <= 0 || minBet > maxBet {
		panic("invalid bet limits")
	}
	if minBuyIn < bigBlind*10 {
		panic("minBuyIn must be at least 10x big blind")
	}

	tableCount++
	id := "table-" + poker.IntToStr(tableCount)

	table := &poker.Table{
		ID:         id,
		Name:       name,
		Creator:    caller.String(),
		Players:    make([]*poker.Player, 0),
		MaxPlayers: maxPlayers,
		SmallBlind: smallBlind,
		BigBlind:   bigBlind,
		MinBet:     minBet,
		MaxBet:     maxBet,
		MinBuyIn:   minBuyIn,
		MaxBuyIn:   minBuyIn * 10,
		State:      poker.StateWaiting,
	}

	tables[id] = table
	tableList = append(tableList, id)

	return id
}

// JoinTable joins an existing table. buyInAmount is in ugnot.
// The caller must send at least buyInAmount ugnot via --send flag.
func JoinTable(cur realm, tableID string, buyInAmount int64) {
	caller := runtime.PreviousRealm().Address()
	table := getTable(tableID)

	if len(table.Players) >= table.MaxPlayers {
		panic("table is full")
	}

	for _, p := range table.Players {
		if p.Address == caller.String() {
			panic("already at this table")
		}
	}

	if buyInAmount < table.MinBuyIn {
		panic("insufficient buy-in amount")
	}
	if buyInAmount > table.MaxBuyIn {
		panic("exceeds max buy-in")
	}

	player := &poker.Player{
		Address:   caller.String(),
		Chips:     buyInAmount,
		IsActive:  true,
		SeatIndex: len(table.Players),
	}

	table.Players = append(table.Players, player)
}

// LeaveTable sends remaining chips back to player wallet
func LeaveTable(cur realm, tableID string) {
	caller := runtime.PreviousRealm().Address()
	table := getTable(tableID)

	for i, p := range table.Players {
		if p.Address == caller.String() {
			if table.State != poker.StateWaiting && !p.HasFolded {
				p.HasFolded = true
			}

			// Send remaining chips back to player (only if realm has funds)
			if p.Chips > 0 {
				b := banker.NewBanker(banker.BankerTypeRealmSend)
				pkgaddr := runtime.CurrentRealm().Address()
				realmCoins := b.GetCoins(pkgaddr)
				hasEnough := false
				for _, c := range realmCoins {
					if c.Denom == "ugnot" && c.Amount >= p.Chips {
						hasEnough = true
						break
					}
				}
				if hasEnough {
					sendCoins := chain.Coins{chain.NewCoin("ugnot", p.Chips)}
					b.SendCoins(pkgaddr, caller, sendCoins)
				}
			}

			table.Players = append(table.Players[:i], table.Players[i+1:]...)

			for j := i; j < len(table.Players); j++ {
				table.Players[j].SeatIndex = j
			}

			if len(table.Players) < 2 && table.State != poker.StateWaiting {
				if len(table.Players) == 1 {
					remaining := table.Players[0]
					remaining.Chips += table.Pot
					table.Pot = 0
				}
				table.State = poker.StateWaiting
				table.Community = nil
			}

			return
		}
	}

	panic("player not found at this table")
}

// ----- Game Flow -----

func StartHand(cur realm, tableID string) {
	table := getTable(tableID)

	if len(table.Players) < 2 {
		panic("need at least 2 players to start")
	}
	if table.State != poker.StateWaiting {
		panic("hand already in progress")
	}

	deck := poker.NewDeck()
	seed := int64(table.HandCount)*31337 + 12345
	deck.Shuffle(seed)

	for _, p := range table.Players {
		p.HasFolded = false
		p.IsAllIn = false
		p.CurrentBet = 0
		cards := deck.Deal(2)
		p.Hand = [2]poker.Card{cards[0], cards[1]}
	}

	table.DeckSeed = seed
	table.Community = make([]poker.Card, 0)
	table.Pot = 0
	table.State = poker.StatePreFlop
	table.HandCount++

	numPlayers := len(table.Players)
	sbIdx := (table.DealerIdx + 1) % numPlayers
	bbIdx := (table.DealerIdx + 2) % numPlayers

	sb := table.SmallBlind
	bb := table.BigBlind

	table.Players[sbIdx].Chips -= sb
	table.Players[sbIdx].CurrentBet = sb
	table.Players[bbIdx].Chips -= bb
	table.Players[bbIdx].CurrentBet = bb
	table.Pot = sb + bb

	table.CurrentTurn = (bbIdx + 1) % numPlayers
}

func PlaceBet(cur realm, tableID string, amount int64) {
	caller := runtime.PreviousRealm().Address()
	table := getTable(tableID)
	player := getPlayerAt(table, caller.String())

	assertPlayerTurn(table, player)

	if amount <= 0 || amount > player.Chips {
		panic("invalid bet amount")
	}
	if amount > table.MaxBet {
		panic("exceeds max bet")
	}

	player.Chips -= amount
	player.CurrentBet += amount
	table.Pot += amount

	advanceTurn(table)
}

func Call(cur realm, tableID string) {
	caller := runtime.PreviousRealm().Address()
	table := getTable(tableID)
	player := getPlayerAt(table, caller.String())

	assertPlayerTurn(table, player)

	maxBet := getMaxCurrentBet(table)
	toCall := maxBet - player.CurrentBet

	if toCall <= 0 {
		panic("nothing to call, use Check instead")
	}

	if toCall > player.Chips {
		table.Pot += player.Chips
		player.CurrentBet += player.Chips
		player.Chips = 0
		player.IsAllIn = true
	} else {
		player.Chips -= toCall
		player.CurrentBet += toCall
		table.Pot += toCall
	}

	advanceTurn(table)
}

func Check(cur realm, tableID string) {
	caller := runtime.PreviousRealm().Address()
	table := getTable(tableID)
	player := getPlayerAt(table, caller.String())

	assertPlayerTurn(table, player)

	maxBet := getMaxCurrentBet(table)
	if player.CurrentBet < maxBet {
		panic("cannot check, there is an outstanding bet")
	}

	advanceTurn(table)
}

func Fold(cur realm, tableID string) {
	caller := runtime.PreviousRealm().Address()
	table := getTable(tableID)
	player := getPlayerAt(table, caller.String())

	assertPlayerTurn(table, player)

	player.HasFolded = true

	activePlayers := countActivePlayers(table)
	if activePlayers == 1 {
		for _, p := range table.Players {
			if !p.HasFolded {
				awardPot(table, p)
				return
			}
		}
	}

	advanceTurn(table)
}

func AllIn(cur realm, tableID string) {
	caller := runtime.PreviousRealm().Address()
	table := getTable(tableID)
	player := getPlayerAt(table, caller.String())

	assertPlayerTurn(table, player)

	amount := player.Chips
	player.CurrentBet += amount
	player.Chips = 0
	player.IsAllIn = true
	table.Pot += amount

	advanceTurn(table)
}

// ----- Admin Functions -----

func SetRakePercent(cur realm, percent int64) {
	caller := runtime.PreviousRealm().Address()
	if caller != admin {
		panic("only admin can set rake")
	}
	if percent < 0 || percent > 500 {
		panic("rake must be 0-500 (0-5%)")
	}
	rakePercent = percent
}

func WithdrawRake(cur realm) int64 {
	caller := runtime.PreviousRealm().Address()
	if caller != admin {
		panic("only admin can withdraw rake")
	}
	amount := rakePool
	rakePool = 0
	return amount
}

// ----- Query Functions -----

func GetTables() string {
	var sb strings.Builder
	sb.WriteString("[")
	for i, id := range tableList {
		t := tables[id]
		if i > 0 {
			sb.WriteString(",")
		}
		sb.WriteString("{")
		sb.WriteString(`"id":"` + t.ID + `"`)
		sb.WriteString(`,"name":"` + t.Name + `"`)
		sb.WriteString(`,"maxPlayers":` + poker.IntToStr(t.MaxPlayers))
		sb.WriteString(`,"currentPlayers":` + poker.IntToStr(len(t.Players)))
		sb.WriteString(`,"smallBlind":` + int64ToStr(t.SmallBlind))
		sb.WriteString(`,"bigBlind":` + int64ToStr(t.BigBlind))
		sb.WriteString(`,"minBet":` + int64ToStr(t.MinBet))
		sb.WriteString(`,"maxBet":` + int64ToStr(t.MaxBet))
		sb.WriteString(`,"minBuyIn":` + int64ToStr(t.MinBuyIn))
		sb.WriteString(`,"maxBuyIn":` + int64ToStr(t.MaxBuyIn))
		sb.WriteString(`,"pot":` + int64ToStr(t.Pot))
		sb.WriteString(`,"state":"` + t.State.String() + `"`)
		sb.WriteString("}")
	}
	sb.WriteString("]")
	return sb.String()
}

func GetTableState(tableID string) string {
	table := getTable(tableID)
	var sb strings.Builder
	sb.WriteString("{")
	sb.WriteString(`"id":"` + table.ID + `"`)
	sb.WriteString(`,"state":"` + table.State.String() + `"`)
	sb.WriteString(`,"pot":` + int64ToStr(table.Pot))
	sb.WriteString(`,"currentTurn":` + poker.IntToStr(table.CurrentTurn))
	sb.WriteString(`,"dealerIdx":` + poker.IntToStr(table.DealerIdx))
	sb.WriteString(`,"players":` + poker.IntToStr(len(table.Players)))
	sb.WriteString("}")
	return sb.String()
}

// ----- Internal Helpers -----

func getTable(id string) *poker.Table {
	table, ok := tables[id]
	if !ok {
		panic("table not found: " + id)
	}
	return table
}

func getPlayerAt(table *poker.Table, addr string) *poker.Player {
	for _, p := range table.Players {
		if p.Address == addr {
			return p
		}
	}
	panic("player not at this table")
}

func assertPlayerTurn(table *poker.Table, player *poker.Player) {
	if table.State == poker.StateWaiting || table.State == poker.StateShowdown {
		panic("not a betting round")
	}
	if player.HasFolded {
		panic("you have folded")
	}
	if player.SeatIndex != table.CurrentTurn {
		panic("not your turn")
	}
}

func getMaxCurrentBet(table *poker.Table) int64 {
	maxBet := int64(0)
	for _, p := range table.Players {
		if p.CurrentBet > maxBet {
			maxBet = p.CurrentBet
		}
	}
	return maxBet
}

func countActivePlayers(table *poker.Table) int {
	count := 0
	for _, p := range table.Players {
		if !p.HasFolded {
			count++
		}
	}
	return count
}

func advanceTurn(table *poker.Table) {
	numPlayers := len(table.Players)
	next := table.CurrentTurn
	for i := 0; i < numPlayers; i++ {
		next = (next + 1) % numPlayers
		p := table.Players[next]
		if !p.HasFolded && !p.IsAllIn {
			table.CurrentTurn = next
			return
		}
	}
	advanceRound(table)
}

func advanceRound(table *poker.Table) {
	for _, p := range table.Players {
		p.CurrentBet = 0
	}

	deck := poker.NewDeck()
	deck.Shuffle(table.DeckSeed + int64(table.State)*7919)
	deck.Deal(len(table.Players) * 2)

	switch table.State {
	case poker.StatePreFlop:
		cards := deck.Deal(3 + len(table.Community))
		table.Community = cards[len(cards)-3:]
		table.State = poker.StateFlop
	case poker.StateFlop:
		deck.Deal(len(table.Community))
		card := deck.DealOne()
		table.Community = append(table.Community, card)
		table.State = poker.StateTurn
	case poker.StateTurn:
		deck.Deal(len(table.Community))
		card := deck.DealOne()
		table.Community = append(table.Community, card)
		table.State = poker.StateRiver
	case poker.StateRiver:
		table.State = poker.StateShowdown
		resolveShowdown(table)
		return
	}

	table.CurrentTurn = (table.DealerIdx + 1) % len(table.Players)
	for i := 0; i < len(table.Players); i++ {
		idx := (table.CurrentTurn + i) % len(table.Players)
		if !table.Players[idx].HasFolded && !table.Players[idx].IsAllIn {
			table.CurrentTurn = idx
			return
		}
	}
}

func resolveShowdown(table *poker.Table) {
	var bestResult poker.HandResult
	var winner *poker.Player

	for _, p := range table.Players {
		if p.HasFolded {
			continue
		}
		result := poker.EvaluateHand(p.Hand, table.Community)
		if winner == nil || poker.CompareHandResults(result, bestResult) > 0 {
			bestResult = result
			winner = p
		}
	}

	if winner != nil {
		awardPot(table, winner)
	}
}

func awardPot(table *poker.Table, winner *poker.Player) {
	rake := (table.Pot * rakePercent) / 10000
	rakePool += rake

	winnings := table.Pot - rake
	winner.Chips += winnings
	table.Pot = 0
	table.RakeCollected += rake

	table.State = poker.StateWaiting
	table.DealerIdx = (table.DealerIdx + 1) % len(table.Players)
	table.Community = nil
}

func int64ToStr(n int64) string {
	return poker.IntToStr(int(n))
}

package poker

import (
	"strings"

	"gno.land/p/demo/poker"
)

// Render displays the poker realm state as Markdown
func Render(path string) string {
	var sb strings.Builder

	if path == "" || path == "/" {
		renderLobby(&sb)
	} else if strings.HasPrefix(path, "table/") {
		tableID := path[6:]
		renderTable(&sb, tableID)
	} else {
		sb.WriteString("# 🃏 GnoPoker\n\n")
		sb.WriteString("Unknown path: " + path + "\n\n")
		sb.WriteString("[Back to Lobby](/r/demo/poker)\n")
	}

	return sb.String()
}

func renderLobby(sb *strings.Builder) {
	sb.WriteString("# 🃏 GnoPoker — Decentralized Texas Hold'em\n\n")
	sb.WriteString("Play poker on gno.land blockchain. Provably fair, GNOT-powered.\n\n")
	sb.WriteString("---\n\n")

	totalPlayers := 0
	totalPot := int64(0)
	for _, id := range tableList {
		t := tables[id]
		totalPlayers += len(t.Players)
		totalPot += t.Pot
	}

	sb.WriteString("## 📊 Platform Stats\n\n")
	sb.WriteString("| Metric | Value |\n")
	sb.WriteString("|--------|-------|\n")
	sb.WriteString("| Tables | " + poker.IntToStr(len(tableList)) + " |\n")
	sb.WriteString("| Players | " + poker.IntToStr(totalPlayers) + " |\n")
	sb.WriteString("| Total Pot | " + int64ToStr(totalPot/1_000_000) + " GNOT |\n")
	sb.WriteString("| Rake | " + int64ToStr(rakePercent/100) + "." + int64ToStr(rakePercent%100) + "% |\n\n")

	sb.WriteString("## 🎰 Active Tables\n\n")
	sb.WriteString("| Name | Players | Blinds | Pot | Status |\n")
	sb.WriteString("|------|---------|--------|-----|--------|\n")

	for _, id := range tableList {
		t := tables[id]
		sb.WriteString("| [" + t.Name + "](/r/demo/poker:table/" + t.ID + ")")
		sb.WriteString(" | " + poker.IntToStr(len(t.Players)) + "/" + poker.IntToStr(t.MaxPlayers))
		sb.WriteString(" | " + int64ToStr(t.SmallBlind/1_000_000) + "/" + int64ToStr(t.BigBlind/1_000_000) + " GNOT")
		sb.WriteString(" | " + int64ToStr(t.Pot/1_000_000) + " GNOT")
		sb.WriteString(" | " + t.State.String() + " |\n")
	}

	sb.WriteString("\n---\n\n")
	sb.WriteString("*Connect your [Adena Wallet](https://adena.app) and join a table!*\n")
}

func renderTable(sb *strings.Builder, tableID string) {
	table, ok := tables[tableID]
	if !ok {
		sb.WriteString("# ❌ Table Not Found\n\n")
		sb.WriteString("Table `" + tableID + "` does not exist.\n\n")
		sb.WriteString("[Back to Lobby](/r/demo/poker)\n")
		return
	}

	sb.WriteString("# 🃏 " + table.Name + "\n\n")
	sb.WriteString("**" + poker.IntToStr(table.MaxPlayers) + "-Max** | ")
	sb.WriteString("State: **" + table.State.String() + "** | ")
	sb.WriteString("Pot: **" + int64ToStr(table.Pot/1_000_000) + " GNOT**\n\n")

	sb.WriteString("## 👥 Players\n\n")
	sb.WriteString("| Seat | Address | Chips | Status |\n")
	sb.WriteString("|------|---------|-------|--------|\n")

	for i, p := range table.Players {
		status := "Active"
		if p.HasFolded {
			status = "Folded"
		} else if p.IsAllIn {
			status = "All-In"
		}
		if i == table.CurrentTurn && table.State != poker.StateWaiting {
			status += " ◀"
		}

		addr := p.Address
		shortAddr := addr[:8] + "..." + addr[len(addr)-4:]

		sb.WriteString("| " + poker.IntToStr(i+1))
		sb.WriteString(" | " + shortAddr)
		sb.WriteString(" | " + int64ToStr(p.Chips/1_000_000) + " GNOT")
		sb.WriteString(" | " + status + " |\n")
	}

	if len(table.Community) > 0 {
		sb.WriteString("\n## 🂠 Community Cards\n\n")
		for _, c := range table.Community {
			sb.WriteString(poker.CardString(c) + " ")
		}
		sb.WriteString("\n")
	}

	sb.WriteString("\n---\n\n")
	sb.WriteString("[← Back to Lobby](/r/demo/poker)\n")
}

package poker

import (
	"chain"
	"chain/banker"
	"chain/runtime"
	"strings"

	"gno.land/p/demo/poker"
)

// ----- State -----
var (
	tables      map[string]*poker.Table
	tableList   []string
	admin       address
	rakePercent int64
	rakePool    int64
	tableCount  int
	deposits    map[string]int64 // address -> deposited ugnot
)

func init() {
	tables = make(map[string]*poker.Table)
	deposits = make(map[string]int64)
	admin = runtime.PreviousRealm().Address()
	rakePercent = 300 // 3% default
}

// RealmAddr returns the realm's address for MsgSend deposits
func RealmAddr() string {
	return runtime.CurrentRealm().Address().String()
}

// Deposit is called after MsgSend to register the deposit
// The caller first sends GNOT via MsgSend to RealmAddr(),
// then calls Deposit() to register it
func Deposit(cur realm) int64 {
	caller := runtime.PreviousRealm().Address()
	b := banker.NewBanker(banker.BankerTypeReadonly)
	pkgaddr := runtime.CurrentRealm().Address()
	realmCoins := b.GetCoins(pkgaddr)
	var realmBalance int64
	for _, c := range realmCoins {
		if c.Denom == "ugnot" {
			realmBalance = c.Amount
			break
		}
	}
	// Track total deposited by this caller
	deposits[caller.String()] = realmBalance
	return realmBalance
}

// GetDeposit returns how much a player has deposited
func GetDeposit(addr string) int64 {
	return deposits[addr]
}



// ----- Lobby Functions -----

func CreateTable(cur realm, name string, smallBlind int64, bigBlind int64, minBet int64, maxBet int64, maxPlayers int, minBuyIn int64) string {
	caller := runtime.PreviousRealm().Address()

	if maxPlayers != 4 && maxPlayers != 6 {
		panic("maxPlayers must be 4 or 6")
	}
	if smallBlind <= 0 || bigBlind <= 0 || smallBlind > bigBlind {
		panic("invalid blind structure")
	}
	if minBet <= 0 || maxBet <= 0 || minBet > maxBet {
		panic("invalid bet limits")
	}
	if minBuyIn < bigBlind*10 {
		panic("minBuyIn must be at least 10x big blind")
	}

	tableCount++
	id := "table-" + poker.IntToStr(tableCount)

	table := &poker.Table{
		ID:         id,
		Name:       name,
		Creator:    caller.String(),
		Players:    make([]*poker.Player, 0),
		MaxPlayers: maxPlayers,
		SmallBlind: smallBlind,
		BigBlind:   bigBlind,
		MinBet:     minBet,
		MaxBet:     maxBet,
		MinBuyIn:   minBuyIn,
		MaxBuyIn:   minBuyIn * 10,
		State:      poker.StateWaiting,
	}

	tables[id] = table
	tableList = append(tableList, id)

	return id
}

// JoinTable joins an existing table. buyInAmount is in ugnot.
// The caller must send at least buyInAmount ugnot via --send flag.
func JoinTable(cur realm, tableID string, buyInAmount int64) {
	caller := runtime.PreviousRealm().Address()
	table := getTable(tableID)

	if len(table.Players) >= table.MaxPlayers {
		panic("table is full")
	}

	for _, p := range table.Players {
		if p.Address == caller.String() {
			panic("already at this table")
		}
	}

	if buyInAmount < table.MinBuyIn {
		panic("insufficient buy-in amount")
	}
	if buyInAmount > table.MaxBuyIn {
		panic("exceeds max buy-in")
	}

	player := &poker.Player{
		Address:   caller.String(),
		Chips:     buyInAmount,
		IsActive:  true,
		SeatIndex: len(table.Players),
	}

	table.Players = append(table.Players, player)
}

// AddChips — rebuy without leaving the table.
// Player sends GNOT via --send flag, chips are added to their stack.
func AddChips(cur realm, tableID string, amount int64) {
	caller := runtime.PreviousRealm().Address()
	table := getTable(tableID)

	for _, p := range table.Players {
		if p.Address == caller.String() {
			if amount <= 0 {
				panic("amount must be positive")
			}
			p.Chips += amount
			p.IsActive = true
			return
		}
	}
	panic("not at this table")
}

// LeaveTable sends chips back to player wallet.
// withdrawAmount = actual chip count from game server (includes winnings).
func LeaveTable(cur realm, tableID string, withdrawAmount int64) {
	caller := runtime.PreviousRealm().Address()
	table := getTable(tableID)

	for i, p := range table.Players {
		if p.Address == caller.String() {
			if table.State != poker.StateWaiting && !p.HasFolded {
				p.HasFolded = true
			}

			// Determine how much to send: use withdrawAmount from game server
			sendBack := withdrawAmount
			if sendBack <= 0 {
				sendBack = p.Chips // fallback to contract's record
			}

			if sendBack > 0 {
				b := banker.NewBanker(banker.BankerTypeRealmSend)
				pkgaddr := runtime.CurrentRealm().Address()
				realmCoins := b.GetCoins(pkgaddr)
				var realmBalance int64
				for _, c := range realmCoins {
					if c.Denom == "ugnot" {
						realmBalance = c.Amount
						break
					}
				}
				// Send the lesser of withdrawAmount or realm balance
				if sendBack > realmBalance {
					sendBack = realmBalance
				}
				if sendBack > 0 {
					coins := chain.Coins{chain.NewCoin("ugnot", sendBack)}
					b.SendCoins(pkgaddr, caller, coins)
				}
			}

			table.Players = append(table.Players[:i], table.Players[i+1:]...)

			for j := i; j < len(table.Players); j++ {
				table.Players[j].SeatIndex = j
			}

			if len(table.Players) < 2 && table.State != poker.StateWaiting {
				if len(table.Players) == 1 {
					remaining := table.Players[0]
					remaining.Chips += table.Pot
					table.Pot = 0
				}
				table.State = poker.StateWaiting
				table.Community = nil
			}

			return
		}
	}

	panic("player not found at this table")
}

// ----- Game Flow -----

func StartHand(cur realm, tableID string) {
	table := getTable(tableID)

	if len(table.Players) < 2 {
		panic("need at least 2 players to start")
	}
	if table.State != poker.StateWaiting {
		panic("hand already in progress")
	}

	deck := poker.NewDeck()
	seed := int64(table.HandCount)*31337 + 12345
	deck.Shuffle(seed)

	for _, p := range table.Players {
		p.HasFolded = false
		p.IsAllIn = false
		p.CurrentBet = 0
		cards := deck.Deal(2)
		p.Hand = [2]poker.Card{cards[0], cards[1]}
	}

	table.DeckSeed = seed
	table.Community = make([]poker.Card, 0)
	table.Pot = 0
	table.State = poker.StatePreFlop
	table.HandCount++

	numPlayers := len(table.Players)
	sbIdx := (table.DealerIdx + 1) % numPlayers
	bbIdx := (table.DealerIdx + 2) % numPlayers

	sb := table.SmallBlind
	bb := table.BigBlind

	table.Players[sbIdx].Chips -= sb
	table.Players[sbIdx].CurrentBet = sb
	table.Players[bbIdx].Chips -= bb
	table.Players[bbIdx].CurrentBet = bb
	table.Pot = sb + bb

	table.CurrentTurn = (bbIdx + 1) % numPlayers
}

func PlaceBet(cur realm, tableID string, amount int64) {
	caller := runtime.PreviousRealm().Address()
	table := getTable(tableID)
	player := getPlayerAt(table, caller.String())

	assertPlayerTurn(table, player)

	if amount <= 0 || amount > player.Chips {
		panic("invalid bet amount")
	}
	if amount > table.MaxBet {
		panic("exceeds max bet")
	}

	player.Chips -= amount
	player.CurrentBet += amount
	table.Pot += amount

	advanceTurn(table)
}

func Call(cur realm, tableID string) {
	caller := runtime.PreviousRealm().Address()
	table := getTable(tableID)
	player := getPlayerAt(table, caller.String())

	assertPlayerTurn(table, player)

	maxBet := getMaxCurrentBet(table)
	toCall := maxBet - player.CurrentBet

	if toCall <= 0 {
		panic("nothing to call, use Check instead")
	}

	if toCall > player.Chips {
		table.Pot += player.Chips
		player.CurrentBet += player.Chips
		player.Chips = 0
		player.IsAllIn = true
	} else {
		player.Chips -= toCall
		player.CurrentBet += toCall
		table.Pot += toCall
	}

	advanceTurn(table)
}

func Check(cur realm, tableID string) {
	caller := runtime.PreviousRealm().Address()
	table := getTable(tableID)
	player := getPlayerAt(table, caller.String())

	assertPlayerTurn(table, player)

	maxBet := getMaxCurrentBet(table)
	if player.CurrentBet < maxBet {
		panic("cannot check, there is an outstanding bet")
	}

	advanceTurn(table)
}

func Fold(cur realm, tableID string) {
	caller := runtime.PreviousRealm().Address()
	table := getTable(tableID)
	player := getPlayerAt(table, caller.String())

	assertPlayerTurn(table, player)

	player.HasFolded = true

	activePlayers := countActivePlayers(table)
	if activePlayers == 1 {
		for _, p := range table.Players {
			if !p.HasFolded {
				awardPot(table, p)
				return
			}
		}
	}

	advanceTurn(table)
}

func AllIn(cur realm, tableID string) {
	caller := runtime.PreviousRealm().Address()
	table := getTable(tableID)
	player := getPlayerAt(table, caller.String())

	assertPlayerTurn(table, player)

	amount := player.Chips
	player.CurrentBet += amount
	player.Chips = 0
	player.IsAllIn = true
	table.Pot += amount

	advanceTurn(table)
}

// ----- Admin Functions -----

func SetRakePercent(cur realm, percent int64) {
	caller := runtime.PreviousRealm().Address()
	if caller != admin {
		panic("only admin can set rake")
	}
	if percent < 0 || percent > 500 {
		panic("rake must be 0-500 (0-5%)")
	}
	rakePercent = percent
}

func WithdrawRake(cur realm) int64 {
	caller := runtime.PreviousRealm().Address()
	if caller != admin {
		panic("only admin can withdraw rake")
	}
	amount := rakePool
	rakePool = 0
	return amount
}

